import { CanonicalDocumentNormalizer } from './CanonicalDocumentNormalizer';

/**
 * SERVIÇO DE DOMÍNIO: FINGERPRINTER (V6 - DNA BLINDADO)
 * --------------------------------------------------------------------------
 * Gera a identidade estrutural definitiva. Uma vez salvo, este DNA é a lei.
 */

export interface StructuralFingerprint {
    columnCount: number;
    delimiter: string;
    headerHash: string | null;
    dataTopology: string;
    canonicalSignature?: string;
    structuralPattern?: string;
}

export const Fingerprinter = {
    detectDelimiter: (line: string): string => {
        if (!line) return ';';
        const candidates = [';', ',', '\t', '|'];
        const counts = candidates.map(char => ({ 
            char, 
            count: line.split(char).length - 1 
        }));
        counts.sort((a, b) => b.count - a.count);
        return counts[0].count > 0 ? counts[0].char : ';';
    },

    /**
     * Gera o DNA estrutural blindado. 
     * Remove ruídos agressivamente para garantir que "Layout igual" = "Hash igual".
     */
    generate: (content: string): StructuralFingerprint | null => {
        if (!content || typeof content !== 'string') return null;

        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return null;

        const firstLine = lines[0];
        const delimiter = Fingerprinter.detectDelimiter(firstLine);
        const cells = firstLine.split(delimiter);

        // 🛡️ NORMALIZAÇÃO CIRÚRGICA: 
        // Remove tudo que não for Alfanumérico puro. 
        // Isso impede que variações de delimitadores ou espaços quebrem o reconhecimento.
        const cleanHeader = firstLine
            .normalize('NFD')
            .replace(/[\u0300-\u036f]/g, '') 
            .replace(/[^A-Z0-9]/gi, '') 
            .toUpperCase();

        let hash = 5381;
        for (let i = 0; i < cleanHeader.length; i++) {
            hash = ((hash << 5) + hash) + cleanHeader.charCodeAt(i);
        }
        const headerHash = Math.abs(hash).toString(36);

        const structuralPattern = CanonicalDocumentNormalizer.generateStructuralPattern(lines);

        return { 
            columnCount: cells.length, 
            delimiter, 
            headerHash, 
            dataTopology: 'FIXED_CONTRACT', // Força a topologia ao contrato salvo
            structuralPattern
        };
    }
};

import { Transaction, FileModel } from '../types';
import { ContractExecutor } from './engine/ContractExecutor';
import { Fingerprinter } from './processors/Fingerprinter';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { TypeResolver } from './processors/TypeResolver';
import { NameResolver } from './processors/NameResolver';
import { Logger } from '../services/monitoringService';

export interface StrategyResult {
    transactions: Transaction[];
    strategyName: string;
    status?: 'MODEL_REQUIRED';
    fileName?: string;
    fingerprint?: any;
    preview?: string;
}

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: any, models?: FileModel[]): boolean;
    parse(content: any, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

/**
 * 🛡️ ESTRATÉGIA DE CONTRATO (V1 - PRIORIDADE MÁXIMA)
 * Garante que modelos aprendidos sejam aplicados com 100% de fidelidade.
 */
export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const fileFp = Fingerprinter.generate(rawText);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && 
            (m.fingerprint.headerHash === fileFp.headerHash)
        );
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const fileFp = Fingerprinter.generate(rawText);

        const model = models?.find(m => 
            m.is_active && 
            (m.fingerprint.headerHash === fileFp?.headerHash)
        );

        if (!model) return [];

        console.log(`[Strategy:CONTRACT] Aplicando padrão gravado: "${model.name}" (v${model.version})`);
        return await ContractExecutor.apply(model, content);
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico (Virtual)',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords = []) => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const lines = rawText.split(/\r?\n/).filter((l: string) => l.trim().length > 0);
        if (lines.length === 0) return [];

        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const grid = lines.map((l: string) => l.split(delimiter));

        const dateIdx = DateResolver.identifyDateColumn(grid);
        const amountIdx = AmountResolver.identifyAmountColumn(grid, [dateIdx]);
        const nameIdx = NameResolver.identifyNameColumn(grid, [dateIdx, amountIdx]);

        const transactions: Transaction[] = [];

        grid.forEach((cols, index) => {
            const rawDate = dateIdx !== -1 ? (cols[dateIdx] || '') : '';
            const rawAmount = amountIdx !== -1 ? (cols[amountIdx] || '') : '';
            const rawDesc = nameIdx !== -1 ? (cols[nameIdx] || '') : cols.join(' ');

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numVal = parseFloat(stdAmount);

            if (isoDate && !isNaN(numVal)) {
                transactions.push({
                    id: `gen-${index}-${Date.now()}`,
                    date: isoDate,
                    description: rawDesc.trim(),
                    rawDescription: cols.join('|'),
                    amount: numVal,
                    originalAmount: rawAmount,
                    cleanedDescription: NameResolver.clean(rawDesc, globalKeywords),
                    contributionType: TypeResolver.resolveFromDescription(rawDesc)
                });
            }
        });
        return transactions;
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: any, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<StrategyResult> => {
        const rawText = content?.__rawText || (typeof content === 'string' ? content : "");
        const source = content?.__source || 'unknown';

        // 1. Prioridade Absoluta: Modelo forçado ou Reconhecido
        if (overrideModel) {
            const txs = await DatabaseModelStrategy.parse(content, 2025, [overrideModel], []);
            return { transactions: txs, strategyName: `Treino: ${overrideModel.name}` };
        }

        const fileFp = Fingerprinter.generate(rawText);
        const targetModel = models.find(m => m.is_active && m.fingerprint.headerHash === fileFp?.headerHash);

        if (targetModel) {
            const txs = await DatabaseModelStrategy.parse(content, 2025, [targetModel], []);
            return { transactions: txs, strategyName: `Contrato: ${targetModel.name}` };
        }

        // 2. Se não tem modelo e não é virtual, BLOQUEIA
        if (source !== 'virtual' && source !== 'gmail') {
            return { 
                status: 'MODEL_REQUIRED',
                fileName: filename,
                fingerprint: fileFp,
                preview: rawText.substring(0, 500),
                transactions: [], 
                strategyName: 'Bloqueio: Sem Modelo'
            };
        }

        // 3. Fallback apenas para dados virtuais
        const txs = GenericStrategy.parse(content, 2025, [], globalKeywords) as Transaction[];
        return { transactions: txs, strategyName: 'Genérico' };
    }
};

import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { NameResolver } from '../processors/NameResolver';
import { TypeResolver } from '../processors/TypeResolver';

/**
 * 📜 CONTRACT EXECUTOR (V20 - FIDELIDADE DETERMINÍSTICA)
 * --------------------------------------------------------------------------
 * Este componente ignora interpretações de IA e executa exatamente o 
 * que foi gravado no mapeamento do modelo.
 */

export const ContractExecutor = {
    /**
     * Aplica as coordenadas do contrato ao conteúdo bruto.
     */
    async apply(model: FileModel, adaptedInput: any): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);

        const { mapping } = model;
        const yearAnchor = DateResolver.discoverAnchorYear(rawText);
        const results: Transaction[] = [];

        // 🚀 EXECUÇÃO RÁPIDA E FIEL
        lines.forEach((line, idx) => {
            // Ignora linhas conforme o contrato (Skip Rows)
            if (idx < (mapping.skipRowsStart || 0)) return;

            const cells = line.split(';'); // O Orchestrator garante que o input venha como CSV virtual

            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";

            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            // Validação mínima de contrato: deve ter data e valor para ser transação
            if (isoDate && !isNaN(numAmount)) {
                results.push({
                    id: `exec-${model.id}-${idx}`,
                    date: isoDate,
                    description: rawDesc.trim(),
                    rawDescription: line,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    // BLINDAGEM: O nome é retornado conforme o contrato, sem limpeza extra
                    cleanedDescription: rawDesc.trim(), 
                    contributionType: TypeResolver.resolveFromDescription(rawDesc),
                    paymentMethod: mapping.paymentMethodColumnIndex !== undefined ? cells[mapping.paymentMethodColumnIndex] : 'OUTROS'
                });
            }
        });

        console.log(`[Executor] ${results.length} registros extraídos fielmente via contrato "${model.name}"`);
        return results;
    }
};
